  ('fire-eq-tech-moex-02280', 'fire-eq-tech', 'fire-eq-tech-moex-102-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依照各類場所消防安全設備檢修及申報作業基準之規定，某光電式局限型三種蓄積型探測器，其標稱蓄 積時間合計為25秒，進行性能檢查時，其動作時間最長在多久範圍以內，方能符合規定？', '["120秒", "90秒", "85秒", "60秒"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "a28a5fe44378", "answer_pdf_sha1": "079fbe44f242", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0709", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02281', 'fire-eq-tech', 'fire-eq-tech-moex-102-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '火災自動警報及防災連動控制設備用火警受信總機，其構造、材質、性能等技術上之規範及試驗方法， 下列敘述何者正確？', '["受信總機之外箱（殼）應為良導體，使用不燃性或耐燃性材料，其厚度應在0.8 mm以上，並設置接地 端子，端子必須能固定線徑1.2 mm以上之電線，且須有接地標示及不得有不必要之開口", "供電源變壓器初級輸入側使用時，非束線之配線導體斷面積最低為0.2 mm2以上，且不可與其他配線結 成束線", "束線之配線時電流密度，絞線應在5 A/mm2以下，單線應在6.2 A/mm2以下", "焊錫以紮接配線為原則，使用繞線時應在6圈以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "a28a5fe44378", "answer_pdf_sha1": "079fbe44f242", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0709", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02282', 'fire-eq-tech', 'fire-eq-tech-moex-102-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '住宅用火災警報器裝置於天花板或樓板者，應距離出風口多少公尺以上？', '["一點五", "一", "零點六", "零點五"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "a28a5fe44378", "answer_pdf_sha1": "079fbe44f242", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0709", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02283', 'fire-eq-tech', 'fire-eq-tech-moex-102-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '有關緊急照明燈的緊急電源之規定，下列敘述何者不正確？', '["使用蓄電池設備時，其容量應能使其持續動作30分鐘以上", "採蓄電池設備與緊急發電機併設方式時，其容量應能使其持續動作分別為10分鐘及30分鐘以上", "天花板及底材使用不燃材料者，緊急電源供電系統之配線，得採一般配線", "緊急照明燈內置蓄電池者，緊急電源供電系統之配線，得採一般配線"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "a28a5fe44378", "answer_pdf_sha1": "079fbe44f242", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0709", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02284', 'fire-eq-tech', 'fire-eq-tech-moex-102-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '有關緩降機的構造與機能之規定，下列敘述何者不正確？', '["緩降機之最大使用載重，應在最大使用人數乘以1,000 nt所得數值以上", "緩降機常溫試驗時，下降速度(m/sec)應在每秒16公分以上150公分以下之範圍內", "緩降機繩索芯線直徑應在0.3公分以上", "移動式緩降機的調速器之重量在12公斤以下"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "a28a5fe44378", "answer_pdf_sha1": "079fbe44f242", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0709", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02285', 'fire-eq-tech', 'fire-eq-tech-moex-102-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '某探測器其裝置場所高度為 9 公尺，依照各類場所消防安全設備設置標準之規定，可以選擇探測器的種 類，下列何者為正確？', '["光電式局限型二種", "光電式局限型三種", "補償式局限型一種", "定溫式特種"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "a28a5fe44378", "answer_pdf_sha1": "079fbe44f242", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0709", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02286', 'fire-eq-tech', 'fire-eq-tech-moex-101-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '依據「消防幫浦認可基準」規定，下列何者為消防幫浦之性能試驗要求內容？', '["幫浦在額定出水量時，在其性能曲線上之全揚程應為額定全揚程之100%以上、125%以下", "幫浦之出水量在額定出水量之150%時，其全揚程應為額定出水量在性能曲線上全揚程之75%以上", "全閉揚程應為額定出水量在性能曲線上全揚程之140%以下", "額定出水量時之全揚程應在設計值之＋15%、-15%內"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "c32a00193b12", "answer_pdf_sha1": "aa4249021090", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "902", "s": "0910", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02287', 'fire-eq-tech', 'fire-eq-tech-moex-101-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '有關消防幫浦之呼水裝置進行外觀檢查時，各項目之規定何者為正確？', '["補給水管口徑應為25A", "溢水用排水管口徑應為50A", "呼水管一般口徑應為50A以上", "從逆止閥中心線至呼水槽底面垂直距離在1.0 m以下時，呼水管口徑應為50A以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "c32a00193b12", "answer_pdf_sha1": "aa4249021090", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "902", "s": "0910", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02288', 'fire-eq-tech', 'fire-eq-tech-moex-101-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '高度超過六十公尺之建築物者，連結送水管採用之中繼幫浦出水量最低限制為每分鐘多少公升？', '["1,600公升", "1,800公升", "2,000公升", "2,400公升"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "c32a00193b12", "answer_pdf_sha1": "aa4249021090", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "902", "s": "0910", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02289', 'fire-eq-tech', 'fire-eq-tech-moex-101-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '一齊開放閥依規定應於控制部動作後，必須在X秒內開啟出水；內徑超過200 mm者，則須於Y秒內開 啟出水，其中X與Y值分別為何？', '["60秒、30秒", "30秒、30秒", "30秒、60秒", "15秒、60秒"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "c32a00193b12", "answer_pdf_sha1": "aa4249021090", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "902", "s": "0910", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
